package main.rice.test;

import java.util.List;
import java.util.Set;

/**
 * A representation of the results of running a series of tests on a series of files.
 */
public class TestResults {

    /**
     * All test cases that were executed; each one is a wrapper around a series of
     * PyObjs.
     */
    private final List<TestCase> allCases;

    /**
     * The results of testing, in the form of a list where the i-th element is the set of
     * integers representing the indices of the files that were caught by that i-th test
     * case in allCases.
     */
    private final List<Set<Integer>> caseToFiles;

    /**
     * A set of integers representing the indices of the files that failed one or more
     * tests in allCases.
     */
    private final Set<Integer> wrongSet;

    /**
     * Constructor for a TestResults object; initializes all fields.
     *
     * @param allCases    all test cases that were executed
     * @param caseToFiles a list where the i-th element is a set of integers representing
     *                    the files that were caught by the i-th test case in allCases
     * @param wrongSet    the set of all files that failed one or more tests in allCases
     */
    public TestResults(List<TestCase> allCases, List<Set<Integer>> caseToFiles,
                       Set<Integer> wrongSet) {
        this.allCases = allCases;
        this.caseToFiles = caseToFiles;
        this.wrongSet = wrongSet;
    }

    /**
     * Returns the index-th test case in allCases, if index is within the bounds of
     * allCases; null otherwise.
     *
     * @param index the index of the test case to be returned
     * @return the index-th test case in allTests, if index is valid; null otherwise
     */
    public TestCase getTestCase(int index) {
        // Make sure the index is in bounds; if it's out of bounds, return null
        if (index >= this.allCases.size() || (this.allCases.size() == 0) || (index < 0)) {
            return null;
        }
        return this.allCases.get(index);
    }

    /**
     * Returns the set of files that failed one or more test cases, where files are
     * represented by their indices.
     *
     * @return the set of files that failed one or more test cases
     */
    public Set<Integer> getWrongSet() {
        return this.wrongSet;
    }

    /**
     * Returns the per-case list of files that each test case caught, where files are
     * represented by their indices.
     *
     * @return the per-case list of files that each test case caught
     */
    public List<Set<Integer>> getCaseToFiles() {
        return this.caseToFiles;
    }
}

package main.rice.test;

import main.rice.obj.APyObj;
import java.util.List;

/**
 * A representation of a test case; a wrapper around its arguments, each of which is an
 * APyObj.
 */
public class TestCase {

    /**
     * The list of arguments (Python objects) comprising this test case.
     */
    private final List<APyObj> args;

    /**
     * Constructor for a TestCase; initializes its list of arguments to the input.
     *
     * @param args the list of arguments (Python objects) comprising this test case
     */
    public TestCase(List<APyObj> args) {
        this.args = args;
    }

    /**
     * Returns the list of arguments comprising this test case.
     *
     * @return the list of arguments comprising this test case
     */
    public List<APyObj> getArgs() {
        return this.args;
    }

    /**
     * Returns a string representation of this test's arguments.
     *
     * @return a string representation of this test's arguments
     */
    @Override
    public String toString() {
        return this.args.toString();
    }

    /**
     * Compares this test's arguments to the input object's arguments (if it's a TestCase)
     * by value.
     *
     * @param obj the object to compare against
     * @return true if this is equivalent by value to obj; false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        // If obj is not a TestCase, it's not equivalent
        if (!(obj instanceof TestCase other)) {
            return false;
        }

        // Compare the lists of arguments for equality
        return this.args.equals(other.getArgs());
    }

    /**
     * Computes a hash code based on this object's value, such that two objects that are
     * considered equal by .equals() will also have the same hash code.
     *
     * @return the hash code for this object
     */
    @Override
    public int hashCode() {
        return this.args.hashCode();
    }
}

package test.rice.node;

import main.rice.node.APyNode;
import main.rice.node.PyBoolNode;
import main.rice.obj.PyBoolObj;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.util.*;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Test cases for the PyBoolNode class.
 * Tests the node that generates PyBoolObj values from domains.
 */
class PyBoolNodeTest {

    private PyBoolNode node;

    @BeforeEach
    void setUp() {
        node = new PyBoolNode();
    }

    // ==================== Domain Getter Tests (0.4 pts total) ====================

    /**
     * Tests that getExDomain returns the extensive domain that was set.
     * (0.2 pts)
     */
    @Test
    void testGetExDomain() {
        List<Integer> exDomain = Arrays.asList(0, 1);
        node.setExDomain(exDomain);
        assertEquals(exDomain, node.getExDomain());
    }

    /**
     * Tests that getRanDomain returns the random domain that was set.
     * (0.2 pts)
     */
    @Test
    void testGetRanDomain() {
        List<Integer> ranDomain = Arrays.asList(0, 1);
        node.setRanDomain(ranDomain);
        assertEquals(ranDomain, node.getRanDomain());
    }

    // ==================== Child Node Tests (0.6 pts total) ====================

    /**
     * Tests that getLeftChild returns null for PyBoolNode (leaf node).
     * (0.3 pts)
     */
    @Test
    void testGetLeftChild() {
        assertNull(node.getLeftChild());
    }

    /**
     * Tests that getRightChild returns null for PyBoolNode (leaf node).
     * (0.3 pts)
     */
    @Test
    void testGetRightChild() {
        assertNull(node.getRightChild());
    }

    // ==================== genExVals Tests (1.5 pts total) ====================

    /**
     * Tests genExVals when domain contains both 0 and 1 (both boolean values).
     * Should return a set containing both PyBoolObj(false) and PyBoolObj(true).
     * (1.0 pts)
     */
    @Test
    void testGenExValsBoth() {
        List<Integer> exDomain = Arrays.asList(0, 1);
        node.setExDomain(exDomain);

        Set<PyBoolObj> result = node.genExVals();

        assertEquals(2, result.size());
        assertTrue(result.contains(new PyBoolObj(false)));
        assertTrue(result.contains(new PyBoolObj(true)));
    }

    /**
     * Tests genExVals when domain contains values that map to opposite booleans.
     * Values outside 0 and 1 should be ignored (return null from getObj).
     * (0.5 pts)
     */
    @Test
    void testGenExValsOpposite() {
        // Only 0 in domain - should only get false
        List<Integer> exDomain = Arrays.asList(0);
        node.setExDomain(exDomain);

        Set<PyBoolObj> result = node.genExVals();

        assertEquals(1, result.size());
        assertTrue(result.contains(new PyBoolObj(false)));
        assertFalse(result.contains(new PyBoolObj(true)));

        // Only 1 in domain - should only get true
        exDomain = Arrays.asList(1);
        node.setExDomain(exDomain);

        result = node.genExVals();

        assertEquals(1, result.size());
        assertFalse(result.contains(new PyBoolObj(false)));
        assertTrue(result.contains(new PyBoolObj(true)));
    }

    // ==================== genRandVal Tests (1.5 pts total) ====================

    /**
     * Tests genRandVal when domain contains both 0 and 1.
     * Should return either PyBoolObj(false) or PyBoolObj(true).
     * (1.0 pts)
     */
    @Test
    void testGenRandValBoth() {
        List<Integer> ranDomain = Arrays.asList(0, 1);
        node.setRanDomain(ranDomain);

        // Run multiple times to verify randomness and valid values
        Set<PyBoolObj> validValues = new HashSet<>();
        validValues.add(new PyBoolObj(false));
        validValues.add(new PyBoolObj(true));

        for (int i = 0; i < 100; i++) {
            PyBoolObj result = node.genRandVal();
            assertNotNull(result);
            assertTrue(validValues.contains(result));
        }
    }

    /**
     * Tests genRandVal when domain contains only one value (0 or 1).
     * (0.5 pts)
     */
    @Test
    void testGenRandValOpposite() {
        // Only 0 - should always get false
        List<Integer> ranDomain = Arrays.asList(0);
        node.setRanDomain(ranDomain);

        for (int i = 0; i < 10; i++) {
            PyBoolObj result = node.genRandVal();
            assertEquals(new PyBoolObj(false), result);
        }

        // Only 1 - should always get true
        ranDomain = Arrays.asList(1);
        node.setRanDomain(ranDomain);

        for (int i = 0; i < 10; i++) {
            PyBoolObj result = node.genRandVal();
            assertEquals(new PyBoolObj(true), result);
        }
    }
}

